package Day1;

public class PositiveOrNegativeNumber {

	public static void main(String[] args) {
		// TODO Auto-generated method 
			
		int num=-3;
		
		if(num>0) 
		{
			System.out.println(" Positive Number");
		}
		else if(num<0) 
		{
			System.out.println(" Negitive Number");
		}
		else 
		{
			System.out.println("Zero");
		}
	}
}
